body:
Thanks for taking the time to report this.

Can you please attach an example that shows the issue or missing feature?  (Must be openly licensed, completely self-contained so can directly run what you provide. Ideally use test_regress format, see https://veripool.org/guide/latest/contributing.html?highlight=test_regress#reporting-bugs)

```
package x_pkg;
typedef  bit unsigned [64-1:0]  x_reg_data_t ;
virtual class x_reg;
   extern virtual task read(output int      status,
                            output x_reg_data_t    value,
                            input int        path);
endclass: x_reg
task x_reg::read(output int      status,
                   output x_reg_data_t    value,
                   input int        path);
endtask: read
endpackage  
package s_c_env_pkg;
class r_reg_p_s_reg_n_doorbell extends x_reg;
endclass : r_reg_p_s_reg_n_doorbell

class r_block_p_s_reg;
rand r_reg_p_s_reg_n_doorbell n_doorbell;
endclass : r_block_p_s_reg
import x_pkg::*;
class r_top_s_reg;
  rand r_block_p_s_reg              p_s[16];
endclass
class s_c_env;
  r_top_s_reg r_reg_model;
endclass: s_c_env
endpackage
package s_c_sequences_pkg;
  import x_pkg::*;  
  import s_c_env_pkg::*;
class s_c_v_regs_seq;          
    s_c_env  m_env;
    virtual task body();
        int unsigned p, h_port, p_port, port, data, rdata; int status;
        foreach (m_env.r_reg_model.p_s[p]) begin
            if (m_env.r_reg_model.p_s[p] == null) begin
            end else begin
                m_env.r_reg_model.p_s[p].n_doorbell.read(status, rdata, 0);
            end
        end
    endtask
endclass
endpackage
```

